{% comment %}
  Render an SVG icon based on forloop.index or product handle.
  Usage: {% render 'service-icon', index: forloop.index %}
         {% render 'service-icon', handle: product.handle %}
{% endcomment %}

{%- assign icon_index = index | default: 1 -%}

{%- if handle contains 'auction' or handle contains 'legal' -%}
  {%- assign icon_index = 1 -%}
{%- elsif handle contains 'rics' or handle contains 'survey' -%}
  {%- assign icon_index = 2 -%}
{%- elsif handle contains 'outlay' -%}
  {%- assign icon_index = 3 -%}
{%- elsif handle contains 'photo' -%}
  {%- assign icon_index = 4 -%}
{%- elsif handle contains 'title' -%}
  {%- assign icon_index = 5 -%}
{%- elsif handle contains 'rent' -%}
  {%- assign icon_index = 6 -%}
{%- elsif handle contains 'tenancy' or handle contains 'agreement' -%}
  {%- assign icon_index = 7 -%}
{%- elsif handle contains 'boost' or handle contains 'rightmove' or handle contains 'zoopla' or handle contains 'listing' -%}
  {%- assign icon_index = 8 -%}
{%- endif -%}

{%- case icon_index -%}

{%- when 1 -%}
  {{- '<!-- Auction Legal Pack: gavel -->' -}}
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
    <path d="M14 4l6 6-9 9-6-6 9-9z"/><path d="M3.5 20.5l3.5-3.5"/><line x1="2" y1="22" x2="6" y2="22"/>
    <path d="M9 3L3 9"/>
  </svg>

{%- when 2 -%}
  {{- '<!-- RICS Survey: magnifying glass + house -->' -}}
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
    <circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/>
    <path d="M8 11h6M11 8v6"/>
  </svg>

{%- when 3 -%}
  {{- '<!-- Outlays: coins / money -->' -}}
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
    <circle cx="12" cy="12" r="10"/><path d="M12 6v2m0 8v2M9.5 9.5A2.5 2.5 0 0112 8a2.5 2.5 0 010 5 2.5 2.5 0 000 5 2.5 2.5 0 002.5-1.5"/>
  </svg>

{%- when 4 -%}
  {{- '<!-- Photography: camera -->' -}}
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
    <path d="M23 19a2 2 0 01-2 2H3a2 2 0 01-2-2V8a2 2 0 012-2h4l2-3h6l2 3h4a2 2 0 012 2z"/>
    <circle cx="12" cy="13" r="4"/>
  </svg>

{%- when 5 -%}
  {{- '<!-- Property Title: document / certificate -->' -}}
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
    <path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/>
    <polyline points="14 2 14 8 20 8"/>
    <line x1="8" y1="13" x2="16" y2="13"/><line x1="8" y1="17" x2="12" y2="17"/>
  </svg>

{%- when 6 -%}
  {{- '<!-- Rent Increase: trending up -->' -}}
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
    <polyline points="23 6 13.5 15.5 8.5 10.5 1 18"/>
    <polyline points="17 6 23 6 23 12"/>
  </svg>

{%- when 7 -%}
  {{- '<!-- Tenancy Agreement: handshake / contract -->' -}}
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
    <path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4 4v2"/>
    <circle cx="9" cy="7" r="4"/>
    <path d="M23 21v-2a4 4 0 00-3-3.87M16 3.13a4 4 0 010 7.75"/>
  </svg>

{%- when 8 -%}
  {{- '<!-- Listing Boost: rocket -->' -}}
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
    <path d="M4.5 16.5c-1.5 1.26-2 5-2 5s3.74-.5 5-2c.71-.84.7-2.13-.09-2.91a2.18 2.18 0 00-2.91-.09z"/>
    <path d="M12 15l-3-3a22 22 0 012-3.95A12.88 12.88 0 0122 2c0 2.72-.78 7.5-6 11a22.35 22.35 0 01-4 2z"/>
    <path d="M9 12H4s.55-3.03 2-4c1.62-1.08 5 0 5 0M12 15v5s3.03-.55 4-2c1.08-1.62 0-5 0-5"/>
  </svg>

{%- else -%}
  {{- '<!-- Generic house -->' -}}
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
    <path d="M3 9l9-7 9 7v11a2 2 0 01-2 2H5a2 2 0 01-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/>
  </svg>
{%- endcase -%}

