{% comment %}
  Product card snippet — used in collection & homepage grids.
  Usage: {% render 'product-card', product: product %}
{% endcomment %}

<div class="service-card">
  <div class="service-card__icon">
    {%- render 'service-icon', handle: product.handle -%}
  </div>

  <h3 class="service-card__title">{{ product.title }}</h3>

  <p class="service-card__desc">
    {%- if product.metafields.custom.short_description != blank -%}
      {{ product.metafields.custom.short_description }}
    {%- else -%}
      {{ product.description | strip_html | truncate: 110 }}
    {%- endif -%}
  </p>

  <div class="service-card__footer">
    <div class="service-card__price">
      {%- if product.price == 0 -%}
        POA<small>Contact us</small>
      {%- else -%}
        {{ product.price | money }}
        {%- if product.compare_at_price > product.price -%}
          <small style="text-decoration:line-through;color:var(--color-text-muted)">{{ product.compare_at_price | money }}</small>
        {%- endif -%}
      {%- endif -%}
    </div>
    <a href="{{ product.url }}" class="btn btn--primary btn--sm">View Details</a>
  </div>
</div>

